import{_ as o,o as a,c as t,a3 as c}from"./chunks/framework.aYYe0dfI.js";const m=JSON.parse('{"title":"Module extract:ast","description":"模块 extract:ast 负责基于 Clang AST 的符号提取，是 C++ 项目解析流水线的核心引擎。它通过自定义的递归 AST 访问器（SymbolExtractorVisitor）和消费者（SymbolExtractorConsumer）来遍历翻译单元，为每个可提取的声明计算唯一标识、源片段边界、词法上下文、文档注释和函数签名，同时收集各类关系（函数调用、成员访问、引用、继承）以及文件依赖。提取结果以 ASTResult 结构体封装，包含符号列表、关系列表和依赖文件集合，而模块唯一的公开入口点为 extract_symbols 函数。","frontmatter":{"title":"Module extract:ast","description":"模块 extract:ast 负责基于 Clang AST 的符号提取，是 C++ 项目解析流水线的核心引擎。它通过自定义的递归 AST 访问器（SymbolExtractorVisitor）和消费者（SymbolExtractorConsumer）来遍历翻译单元，为每个可提取的声明计算唯一标识、源片段边界、词法上下文、文档注释和函数签名，同时收集各类关系（函数调用、成员访问、引用、继承）以及文件依赖。提取结果以 ASTResult 结构体封装，包含符号列表、关系列表和依赖文件集合，而模块唯一的公开入口点为 extract_symbols 函数。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/extract/ast.md","filePath":"zh/clore/modules/extract/ast.md"}'),r={name:"zh/clore/modules/extract/ast.md"};function d(l,e,i,s,n,u){return a(),t("div",null,[...e[0]||(e[0]=[c('<h1 id="module-extract-ast" tabindex="-1">Module <code>extract:ast</code> <a class="header-anchor" href="#module-extract-ast" aria-label="Permalink to &quot;Module `extract:ast`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>模块 <code>extract:ast</code> 负责基于 Clang AST 的符号提取，是 C++ 项目解析流水线的核心引擎。它通过自定义的递归 AST 访问器（<code>SymbolExtractorVisitor</code>）和消费者（<code>SymbolExtractorConsumer</code>）来遍历翻译单元，为每个可提取的声明计算唯一标识、源片段边界、词法上下文、文档注释和函数签名，同时收集各类关系（函数调用、成员访问、引用、继承）以及文件依赖。提取结果以 <code>ASTResult</code> 结构体封装，包含符号列表、关系列表和依赖文件集合，而模块唯一的公开入口点为 <code>extract_symbols</code> 函数。</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./compiler"><code>extract:compiler</code></a></li><li><a href="./model"><code>extract:model</code></a></li><li><code>std</code></li><li><a href="./../support/"><code>support</code></a></li></ul><h2 id="imported-by" tabindex="-1">Imported By <a class="header-anchor" href="#imported-by" aria-label="Permalink to &quot;Imported By&quot;">​</a></h2><ul><li><a href="./cache"><code>extract:cache</code></a></li></ul><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-extract-asterror" tabindex="-1"><code>clore::extract::ASTError</code> <a class="header-anchor" href="#clore-extract-asterror" aria-label="Permalink to &quot;`clore::extract::ASTError`&quot;">​</a></h3><p>Declaration: <code>extract/ast.cppm:26</code></p><p>Definition: <code>extract/ast.cppm:26</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>结构体 <code>clore::extract::ASTError</code> 的实现是一个仅包含单个 <code>std::string message</code> 成员的聚合体，其内部结构完全依赖于标准字符串的存储和生命周期管理。该设计使得错误消息能够以零额外开销的方式被动态构造、拷贝和移动，编译器自动生成的默认构造函数、析构函数以及拷贝/移动赋值运算符保证了成员的正确初始化和资源释放，无需自定义特殊成员函数。关于不变性，<code>message</code> 字段可以持有任何 UTF-8 或 ASCII 文本，不要求非空或特定格式，结构体本身不维护错误码、层级或上下文信息，其语义完全由外层提取逻辑解释。</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li><code>message</code> 成员始终包含有效的错误描述字符串。</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>message</code></li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>作为 <code>clore::extract</code> 命名空间中错误处理的结果类型使用。</li></ul><h3 id="clore-extract-astresult" tabindex="-1"><code>clore::extract::ASTResult</code> <a class="header-anchor" href="#clore-extract-astresult" aria-label="Permalink to &quot;`clore::extract::ASTResult`&quot;">​</a></h3><p>Declaration: <code>extract/ast.cppm:37</code></p><p>Definition: <code>extract/ast.cppm:37</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>结构体 <code>clore::extract::ASTResult</code> 是一个纯数据聚合体，其内部直接暴露三个公有成员：<code>symbols</code>（类型为 <code>std::vector&lt;SymbolInfo&gt;</code>）、<code>relations</code>（类型为 <code>std::vector&lt;ExtractedRelation&gt;</code>）以及 <code>dependencies</code>（类型为 <code>std::vector&lt;std::string&gt;</code>）。这些字段分别负责承载从 AST 中提取出的符号信息、元素间的关联关系以及外部依赖名列表。该结构体不包含任何自定义构造函数、析构函数或成员函数，其所有成员均可通过直接初始化或聚合初始化来赋值，因此实例化时无需特殊逻辑。</p><p>由于 <code>ASTResult</code> 仅依赖标准库容器，其内存布局完全由编译器决定，且不存在任何需要运行时维护的不变式。通常，各个字段会在提取流程中被顺序填充，并在最终使用时协同解释：<code>symbols</code> 与 <code>relations</code> 通过索引或 ID 相关联，而 <code>dependencies</code> 则独立提供后续编译或分析所需的依赖项集合。该结构体在设计上仅作为数据传输的中间容器，不涉及深拷贝控制或资源管理——由容器本身负责其内部元素的析构与移动语义。</p><h4 id="invariants-1" tabindex="-1">Invariants <a class="header-anchor" href="#invariants-1" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>字段均为公共向量，可自由读写</li><li>无显式不变量约束</li></ul><h4 id="key-members-1" tabindex="-1">Key Members <a class="header-anchor" href="#key-members-1" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>symbols</code></li><li><code>relations</code></li><li><code>dependencies</code></li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>作为提取管道的输出类型</li><li>由分析函数填充并返回</li><li>消费者遍历各向量以获取提取结果</li></ul><h3 id="clore-extract-extractedrelation" tabindex="-1"><code>clore::extract::ExtractedRelation</code> <a class="header-anchor" href="#clore-extract-extractedrelation" aria-label="Permalink to &quot;`clore::extract::ExtractedRelation`&quot;">​</a></h3><p>Declaration: <code>extract/ast.cppm:30</code></p><p>Definition: <code>extract/ast.cppm:30</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p><code>ExtractedRelation</code> 是一个仅包含数据的结构体，用于表示在 AST 提取过程中发现的一条二元关系。该结构体的核心字段为两个 <code>SymbolID</code> 类型成员 <code>from</code> 和 <code>to</code>，分别代表关系中的源和目标符号。另外两个布尔成员 <code>is_call</code> 和 <code>is_inheritance</code> 标记关系的具体语义：当 <code>is_call</code> 为真时，表示 <code>from</code> 调用了 <code>to</code>；当 <code>is_inheritance</code> 为真时，表示 <code>from</code> 派生于 <code>to</code>。虽然在设计上这两个标志通常不应同时为真，但结构体本身并不强制这一不变性，调用方应确保关系的类型是明确的。</p><h4 id="invariants-2" tabindex="-1">Invariants <a class="header-anchor" href="#invariants-2" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li><code>from</code> 和 <code>to</code> 必须为有效的 <code>SymbolID</code></li><li><code>is_call</code> 和 <code>is_inheritance</code> 至少一个为 true 或均为 false</li></ul><h4 id="key-members-2" tabindex="-1">Key Members <a class="header-anchor" href="#key-members-2" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>from</code>：关系的源符号标识</li><li><code>to</code>：关系的目标符号标识</li><li><code>is_call</code>：是否为调用关系</li><li><code>is_inheritance</code>：是否为继承关系</li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>用于构建符号之间的调用图</li><li>用于记录继承层次结构</li><li>在提取阶段填充此结构体以描述符号间依赖</li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-extract-extract-symbols" tabindex="-1"><code>clore::extract::extract_symbols</code> <a class="header-anchor" href="#clore-extract-extract-symbols" aria-label="Permalink to &quot;`clore::extract::extract_symbols`&quot;">​</a></h3><p>Declaration: <code>extract/ast.cppm:43</code></p><p>Definition: <code>extract/ast.cppm:669</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>该函数是符号提取的入口点，内部串联了编译器实例的创建、前端选项的强制调整（将<code>ProgramAction</code>设为<code>clang::frontend::ParseSyntaxOnly</code>并清空输出路径）、以及<code>SymbolExtractorAction</code>的调度执行。依赖<code>create_compiler_instance</code>构建<code>clang::CompilerInstance</code>，并使用<code>collect_dependency_files</code>从<code>SourceManager</code>提取文件依赖。控制流首先检查<code>entry.arguments</code>是否为空，然后依次调用<code>SymbolExtractorAction</code>的<code>BeginSourceFile</code>、<code>Execute</code>和<code>EndSourceFile</code>，每一步失败均返回<code>std::unexpected</code>。提取出的原生<code>RelationEdge</code>列表随后被转换为<code>ExtractedRelation</code>结构，填充<code>from</code>、<code>to</code>、<code>is_call</code>和<code>is_inheritance</code>字段，从而解耦内部枚举类型。</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Creates and mutates a compiler instance (via <code>create_compiler_instance</code> and frontend option modifications)</li><li>Reads source files and includes via the clang frontend during extraction</li><li>Populates the <code>ASTResult</code> output with symbols, relations, and dependency file paths</li><li>Invokes <code>collect_dependency_files</code> which reads the source manager</li><li>May produce diagnostics or cache results indirectly through clang infrastructure</li></ul><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>The <code>entry</code> parameter of type <code>CompileEntry</code> (its <code>file</code>, <code>arguments</code> fields)</li><li>The filesystem: source file and its transitive includes via clang</li><li>Compiler configuration and toolchain (via <code>create_compiler_instance</code>)</li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>The local <code>result</code> object of type <code>ASTResult</code> (its <code>symbols</code>, <code>dependencies</code>, <code>relations</code> sub-objects)</li><li>The local <code>raw_relations</code> vector of <code>RelationEdge</code></li><li>The compiler instance&#39;s frontend options (<code>ProgramAction</code>, <code>OutputFile</code>, <code>ModuleOutputPath</code>)</li></ul><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to extract symbols from a single compile entry</li><li>Called as part of a larger extraction pipeline (e.g., <code>extract_project_async</code>)</li><li>Returns an <code>expected</code> that callers handle for success or error</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p><code>extract:ast</code> 模块实现了从 Clang AST 中提取符号与关系的核心逻辑。它导入 <code>extract:compiler</code>（编译数据库）、<code>extract:model</code>（结果数据模型）、<code>support</code>（基础工具）和标准库。内部采用三层结构：底层为一组匿名命名空间中的辅助函数（如符号 ID 计算、声明分类、文档注释提取、签名构建、源码片段范界计算、依赖文件收集等）；中间层定义了 <code>SymbolExtractorVisitor</code>（基于 <code>RecursiveASTVisitor</code> 的遍历器，负责访问声明、调用、引用、成员表达式并记录符号与关系）、<code>SymbolExtractorConsumer</code>（接收翻译单元并驱动访问器）和 <code>SymbolExtractorAction</code>（触发入口）；顶层公开函数 <code>extract_symbols</code> 接收项目标识符并返回状态码，填充 <code>ASTResult</code> 结构（内含 <code>symbols</code>、<code>relations</code>、<code>dependencies</code> 字段）。</p><p>提取过程中，每个声明均通过 <code>compute_symbol_id</code> 获得整数 ID，依赖收集通过 <code>collect_dependency_files</code> 解析文件包含；关系类型使用 <code>RelationKind</code> 枚举（<code>Inheritance</code>、<code>Call</code>、<code>Reference</code>），并由 <code>RelationEdge</code> 与 <code>ExtractedRelation</code> 中间结构承载，最终归入 <code>ASTResult</code>。辅助结构 <code>SourceSnippetBounds</code> 与 <code>LexicalContextInfo</code> 分别用于记录源码区域和词法上下文。这种分解方式将 AST 遍历、元数据计算与数据汇总清晰分离，便于维护与测试。</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./compiler">Module extract:compiler</a></li><li><a href="./model">Module extract:model</a></li><li><a href="./../support/">Module support</a></li></ul>',61)])])}const p=o(r,[["render",d]]);export{m as __pageData,p as default};
